.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 96px;
  height: 96px;
  border-radius: 22px;
  /* Ensure touch targets meet the 44px minimum (96px already exceeds it) */
  touch-action: none;
  -webkit-user-select: none;
  user-select: none;
}

/* Mobile: slightly smaller tiles on very narrow screens */
@media (max-width: 360px) {
  .shape-tile {
    width: 80px;
    height: 80px;
    border-radius: 18px;
  }
}

